class Solution(object):
    def minimumOperations(self, grid):
        m, n = len(grid), len(grid[0])
        INF = float('inf')

        def col_costs(j):
            costs = [m] * 10
            for r in range(m):
                costs[grid[r][j]] -= 1
            return costs

        prev = col_costs(0)

        for j in range(1, n):
            costs_j = col_costs(j)
            min1 = min2 = INF
            min1_c = -1
            for pc in range(10):
                if prev[pc] < min1:
                    min2 = min1
                    min1 = prev[pc]
                    min1_c = pc
                elif prev[pc] < min2:
                    min2 = prev[pc]
            curr = [0] * 10
            for c in range(10):
                best = min1 if min1_c != c else min2
                curr[c] = best + costs_j[c]
            prev = curr

        return min(prev)
